            margin-top: 20px;
            font-size: 18px;
            color: #bb86fc;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Visualizer</h1>

    <div class="controls">
        <button id="sort">Sort</button>
        <button id="shuffle">Shuffle</button>
        <button id="reset">Reset</button>
    </div>

    <div class="visualizer-container" id="bars"></div>

    <div class="status" id="status">Ready to sort</div>

    <script>
        // Visualizer state
        let array = [];
        let isSorting = false;
        let sortingAlgorithm = null;

        // DOM elements
        const barsContainer = document.getElementById('bars');
        const sortButton = document.getElementById('sort');
        const shuffleButton = document.getElementById('shuffle');
        const resetButton = document.getElementById('reset');
        const statusElement = document.getElementById('status');

        // Initialize with a default array
        function initializeArray(size = 20, maxValue = 100) {
            array = [];
            for (let i = 0; i < size; i++) {
                array.push(Math.floor(Math.random() * maxValue) + 1);
            }
            renderBars();
            isSorting = false;
        }

        // Render the bars based on current array
        function renderBars() {
            barsContainer.innerHTML = '';

            const maxVal = Math.max(...array);

            array.forEach(value => {
                const bar = document.createElement('div');
                bar.className = 'bar';
                bar.setAttribute('data-value', value);

                // Calculate height as percentage of max value
                const heightPercentage = (value / maxVal) * 100;
                bar.style.height = `${heightPercentage}%`;

                barsContainer.appendChild(bar);
            });
        }

        // Check if array is sorted
        function isSorted() {
            for (let i = 0; i < array.length - 1; i++) {
                if (array[i] > array[i + 1]) {
                    return false;
                }
            }
            return true;
        }

        // Bubble sort implementation with step-by-step execution
        class BubbleSort {
            constructor(arr) {
                this.array = arr.slice();
                this.n = this.array.length;
                this.i = 0;
                this.j = 0;
                this.sorted = false;
            }

            nextStep() {
                if (this.sorted) return true;

                // Check if fully sorted
                if (this.i >= this.n - 1) {
                    this.sorted = true;
                    array = this.array.slice();
                    renderBars();
                    return true;
                }

                // Compare adjacent elements
                if (this.j >= this.n - this.i - 1) {
                    this.j = 0;
                    this.i++;
                    return false;
                }

                // Highlight bars being compared
                const bars = document.querySelectorAll('.bar');
                if (bars[this.j]) bars[this.j].classList.add('comparing');
                if (bars[this.j + 1]) bars[this.j + 1].classList.add('comparing');

                setTimeout(() => {
                    if (bars[this.j]) bars[this.j].classList.remove('comparing');
                    if (bars[this.j + 1]) bars[this.j + 1].classList.remove('comparing');
                }, 200);

                // Compare and potentially swap
                if (this.array[this.j] > this.array[this.j + 1]) {
                    // Swap elements
                    const temp = this.array[this.j];
                    this.array[this.j] = this.array[this.j + 1];
                    this.array[this.j + 1] = temp;

                    // Highlight bars being swapped
                    if (bars[this.j]) bars[this.j].classList.add('swapping');
                    if (bars[this.j + 1]) bars[this.j + 1].classList.add('swapping');

                    setTimeout(() => {
                        renderBars();
                        if (bars[this.j]) bars[this.j].classList.remove('swapping');
                        if (bars[this.j + 1]) bars[this.j + 1].classList.remove('swapping');
                    }, 200);
                }

                this.j++;
                return false;
            }
        }

        // Merge sort implementation with step-by-step execution
        class MergeSort {
            constructor(arr) {
                this.array = arr.slice();
                this.tempArray = new Array(this.array.length);
                this.sorted = false;
                this.mergeStep = 0;
                this.currentSize = 1;
                this.leftStart = 0;

                // For animation
                this.animationQueue = [];
                this.buildMergeSteps(0, this.array.length - 1);
            }

            buildMergeSteps(left, right) {
                if (left < right) {
                    const mid = Math.floor((left + right) / 2);
                    this.buildMergeSteps(left, mid);
                    this.buildMergeSteps(mid + 1, right);

                    // Record merge operation
                    this.animationQueue.push({
                        type: 'merge',
                        left,
                        mid,
                        right
                    });
                }
            }

            nextStep() {
                if (this.sorted) return true;

                if (this.mergeStep >= this.animationQueue.length) {
                    this.sorted = true;
                    array = this.array.slice();
                    renderBars();
                    return true;
                }

                const step = this.animationQueue[this.mergeStep];

                // Perform merge operation
                let i = step.left;
                let j = step.mid + 1;
                let k = step.left;

                while (i <= step.mid && j <= step.right) {
                    // Highlight bars being compared
                    const bars = document.querySelectorAll('.bar');
                    if (bars[i]) bars[i].classList.add('comparing');
                    if (bars[j]) bars[j].classList.add('comparing');

                    setTimeout(() => {
                        if (bars[i]) bars[i].classList.remove('comparing');
                        if (bars[j]) bars[j].classList.remove('comparing');
                    }, 200);

                    if (this.array[i] <= this.array[j]) {
                        this.tempArray[k++] = this.array[i++];
                    } else {
                        this.tempArray[k++] = this.array[j++];
                    }
                }

                while (i <= step.mid) {
                    this.tempArray[k++] = this.array[i++];
                }

                while (j <= step.right) {
                    this.tempArray[k++] = this.array[j++];
                }

                // Copy merged elements back
                for (let p = step.left; p <= step.right; p++) {
                    this.array[p] = this.tempArray[p];
                }

                // Update animation state
                this.mergeStep++;

                setTimeout(() => {
                    renderBars();
                }, 200);

                return false;
            }
        }

        // Quick sort implementation with step-by-step execution
        class QuickSort {
            constructor(arr) {
                this.array = arr.slice();
                this.sorted = false;
                this.stack = [{low: 0, high: this.array.length - 1}];
                this.partitionStep = 0;
                this.currentLow = 0;
                this.currentHigh = 0;
                this.i = 0;
                this.j = 0;
            }

            nextStep() {
                if (this.sorted) return true;

                // Check if fully sorted
                let isFullySorted = true;
                for (let k = 0; k < this.array.length - 1; k++) {
                    if (this.array[k] > this.array[k + 1]) {
                        isFullySorted = false;
                        break;
                    }
                }

                if (isFullySorted) {
                    this.sorted = true;
                    array = this.array.slice();
                    renderBars();
                    return true;
                }

                // Process stack
                while (this.stack.length > 0) {
                    const current = this.stack.pop();
                    const low = current.low;
                    const high = current.high;

                    if (low < high) {
                        this.currentLow = low;
                        this.currentHigh = high;
                        this.i = low - 1;
                        this.j = low;

                        // Partition
                        const pivot = this.array[high];

                        // Highlight pivot
                        const bars = document.querySelectorAll('.bar');
                        if (bars[high]) bars[high].classList.add('comparing');

                        setTimeout(() => {
                            if (bars[high]) bars[high].classList.remove('comparing');
                        }, 200);

                        while (this.j < high) {
                            // Highlight bars being compared
                            const bars = document.querySelectorAll('.bar');
                            if (bars[this.j]) bars[this.j].classList.add('comparing');
                            if (bars[high]) bars[high].classList.add('comparing');

                            setTimeout(() => {
                                if (bars[this.j]) bars[this.j].classList.remove('comparing');
                                if (bars[high]) bars[high].classList.remove('comparing');
                            }, 200);

                            if (this.array[this.j] < pivot) {
                                this.i++;
                                // Swap
                                const temp = this.array[this.i];
                                this.array[this.i] = this.array[this.j];
                                this.array[this.j] = temp;

                                // Highlight swap
                                const bars = document.querySelectorAll('.bar');
                                if (bars[this.i]) bars[this.i].classList.add('swapping');
                                if (bars[this.j]) bars[this.j].classList.add('swapping');

                                setTimeout(() => {
                                    renderBars();
                                    if (bars[this.i]) bars[this.i].classList.remove('swapping');
                                    if (bars[this.j]) bars[this.j].classList.remove('swapping');
                                }, 200);
                            }
                            this.j++;
                        }

                        // Swap pivot into position
                        const temp = this.array[this.i + 1];
                        this.array[this.i + 1] = this.array[high];
                        this.array[high] = temp;

                        // Highlight swap
                        const bars = document.querySelectorAll('.bar');
                        if (bars[this.i + 1]) bars[this.i + 1].classList.add('swapping');
                        if (bars[high]) bars[high].classList.add('swapping');

                        setTimeout(() => {
                            renderBars();
                            if (bars[this.i + 1]) bars[this.i + 1].classList.remove('swapping');
                            if (bars[high]) bars[high].classList.remove('swapping');

                            // Add subarrays to stack
                            this.stack.push({low: low, high: this.i});
                            this.stack.push({low: this.i + 2, high: high});
                        }, 200);

                        return false;
                    }
                }

                this.sorted = true;
                array = this.array.slice();
                renderBars();
                return true;
            }
        }

        // Expose the API on window
        window.viz = {
            array() {
                return array.slice();
            },

            setArray(a) {
                array = a.slice();
                renderBars();
                isSorting = false;
                statusElement.textContent = 'Ready to sort';
            },

            sortStep() {
                if (isSorted()) {
                    return true;
                }

                // Start sorting with bubble sort if not already sorting
                if (!sortingAlgorithm) {
                    sortingAlgorithm = new BubbleSort(array);
                }

                const done = sortingAlgorithm.nextStep();

                if (done) {
                    isSorting = false;
                    statusElement.textContent = 'Sorted!';
                    sortButton.disabled = false;
                } else {
                    isSorting = true;
                    statusElement.textContent = 'Sorting...';
                }

                return done;
            },

            sorted() {
                return isSorted();
            }
        };

        // Event listeners
        shuffleButton.addEventListener('click', () => {
            if (isSorting) return;

            const currentArray = window.viz.array();
            // Fisher-Yates shuffle
            for (let i = currentArray.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [currentArray[i], currentArray[j]] = [currentArray[j], currentArray[i]];
            }

            window.viz.setArray(currentArray);
            statusElement.textContent = 'Shuffled';
        });

        resetButton.addEventListener('click', () => {
            if (isSorting) return;

            initializeArray();
            statusElement.textContent = 'Reset to default array';
        });

        sortButton.addEventListener('click', () => {
            if (isSorted()) {
                // Shuffle first if already sorted
                shuffleButton.click();
            }

            isSorting = true;
            sortingAlgorithm = new BubbleSort(array);
            sortButton.disabled = true;

            // Sort step by step
            function processSortStep() {
                if (!isSorting) return;

                const done = window.viz.sortStep();
                if (done) {
                    statusElement.textContent = 'Sorting complete!';
                } else {
                    setTimeout(processSortStep, 100);
                }
            }

            processSortStep();
        });

        // Initialize on load
        initializeArray();
    </script>
</body>
</html>
